import { Tooltip } from "radix-ui";

export type TooltipProviderProps = React.ComponentProps<typeof Tooltip.Provider>;

export const TooltipProvider = (props: TooltipProviderProps) => {
  return <Tooltip.Provider {...props} />;
};

import "./tooltip.css";

import { Tooltip } from "radix-ui";

export type TooltipRootProps = React.ComponentProps<typeof Tooltip.Root>;

export const TooltipRoot = (props: TooltipRootProps) => {
  return <Tooltip.Root {...props} />;
};

import { Tooltip } from "radix-ui";

export type TooltipTriggerProps = React.ComponentProps<typeof Tooltip.Trigger>;

export const TooltipTrigger = (props: TooltipTriggerProps) => {
  return <Tooltip.Trigger asChild {...props} />;
};

import { Tooltip } from "radix-ui";
import { cn } from "tailwind-variants";

import { tooltipVariants } from "./tooltip.variants";

export type TooltipContentProps = React.ComponentProps<typeof Tooltip.Content>;

export const TooltipContent = ({ className, sideOffset = 4, ...props }: TooltipContentProps) => {
  const { content } = tooltipVariants();

  return (
    <Tooltip.Portal>
      <Tooltip.Content className={cn(content(), className)} sideOffset={sideOffset} {...props} />
    </Tooltip.Portal>
  );
};

import { tv, type VariantProps } from "tailwind-variants";

export const tooltipVariants = tv({
  slots: {
    content: "tooltip__content",
  },
});

export type TooltipVariants = VariantProps<typeof tooltipVariants>;

.tooltip__content {
  @apply bg-primary text-primary-foreground z-50 overflow-hidden rounded-md px-3 py-1.5 text-xs;

  &[data-state="delayed-open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }

  &[data-side="bottom"] {
    @apply slide-in-from-top-2;
  }

  &[data-side="left"] {
    @apply slide-in-from-right-2;
  }

  &[data-side="right"] {
    @apply slide-in-from-left-2;
  }

  &[data-side="top"] {
    @apply slide-in-from-bottom-2;
  }
}

import { TooltipContent } from "./tooltip-content";
import { TooltipProvider } from "./tooltip-provider";
import { TooltipRoot } from "./tooltip-root";
import { TooltipTrigger } from "./tooltip-trigger";

export const Tooltip = {
  Content: TooltipContent,
  Provider: TooltipProvider,
  Root: TooltipRoot,
  Trigger: TooltipTrigger,
};

export { TooltipContent, TooltipProvider, TooltipRoot, TooltipTrigger };

export type { TooltipContentProps } from "./tooltip-content";

export type { TooltipProviderProps } from "./tooltip-provider";
export type { TooltipRootProps } from "./tooltip-root";
export type { TooltipTriggerProps } from "./tooltip-trigger";
export { type TooltipVariants, tooltipVariants } from "./tooltip.variants";
